const response = $input.first().json;
const category = $('Loop Over Queries').item.json.category;
const results = response.organic_results || [];

if (results.length === 0) return [];

// Filter out results from non-English or irrelevant sources
const skipDomains = ['hindi', 'arabic', 'french', 'german', 'spanish', 'portuguese', 'russian', 'chinese', 'japanese', 'korean', 'news18', 'ndtv', 'timesofindia', 'indiatoday', 'reddit.com/r/memes', 'twitter.com', 'facebook.com'];

const filtered = results.filter(r => {
  const link = (r.link || '').toLowerCase();
  const source = (r.displayed_link || '').toLowerCase();
  return !skipDomains.some(d => link.includes(d) || source.includes(d));
});

if (filtered.length === 0) return [];

return filtered.slice(0, 8).map(r => ({
  json: {
    category,
    title: r.title || '',
    snippet: r.snippet || '',
    link: r.link || '',
    source: r.displayed_link || '',
    date: r.date || ''
  }
}));

