const searchResult = $('Format Search Results').item.json;
const claudeResponse = $input.first().json;

let extracted;
try {
  const aiText = claudeResponse.content?.[0]?.text || '{}';
  const clean = aiText.replace(/```json\n?|```\n?/g, '').trim();
  extracted = JSON.parse(clean);
} catch (e) {
  return [];
}

// Skip if all unknown
if (extracted.gameName === 'Unknown' && extracted.publisher === 'Unknown' && extracted.developer === 'Unknown') {
  return [];
}

// If no game name but publisher known, use publisher as placeholder
if (!extracted.gameName || extracted.gameName === 'Unknown') {
  if (extracted.publisher && extracted.publisher !== 'Unknown') {
    extracted.gameName = extracted.publisher + ' (TBD)';
  } else if (extracted.developer && extracted.developer !== 'Unknown') {
    extracted.gameName = extracted.developer + ' (TBD)';
  } else {
    return [];
  }
}

// Skip parse errors
if (extracted.gameName === 'Parse Error') return [];

// Skip low relevance only
if (extracted.relevance === 'LOW') return [];

// Duplicate detection
const existingGames = $('Read Existing Games').all()
  .map(i => i.json['Game Name']?.toLowerCase().trim())
  .filter(Boolean);

if (existingGames.includes(extracted.gameName?.toLowerCase().trim())) {
  return [];
}

const now = new Date().toISOString();

return [{
  json: {
    'Date Found': now,
    'Status': 'New',
    'Relevance': extracted.relevance,
    'Release Status': extracted.releaseStatus,
    'Budget Signal': extracted.budgetSignal,
    'Game Name': extracted.gameName,
    'Developer': extracted.developer,
    'Publisher': extracted.publisher,
    'Release Type': extracted.releaseType,
    'Release Window': extracted.releaseWindow,
    'Platform': extracted.platform,
    'Sales Angle': extracted.salesAngle,
    'Outreach Note': extracted.outreachNote,
    'Confidence': extracted.confidence,
    'Category': searchResult.category,
    'Source Article': searchResult.link,
    'Article Title': searchResult.title,
    'Contact Found': 'No',
    'Contact Name': '',
    'Contact Email': '',
    'Contact LinkedIn': '',
    'Notes': ''
  }
}];
